/workspace/app-builder/style.css.content:
:root {
  --bg: #16181d;
  --panel: #1e2129;
  --panel-2: #232733;
  --border: #2e3342;
  --text: #e8eaf0;
  --muted: #9aa1b2;
  --accent: #4f8cff;
  --accent-hover: #3d78ec;
  --danger: #e5534b;
  --radius: 8px;
}

* { box-sizing: border-box; }

html, body {
  margin: 0;
  height: 100%;
  font-family: "Segoe UI", system-ui, -apple-system, sans-serif;
  font-size: 14px;
  background: var(--bg);
  color: var(--text);
}

body {
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

/* ---------- Top bar ---------- */
.topbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 16px;
  background: var(--panel);
  border-bottom: 1px solid var(--border);
}

.brand {
  display: flex;
  align-items: center;
  gap: 8px;
  font-weight: 600;
  font-size: 15px;
}

.brand-dot {
  width: 12px;
  height: 12px;
  border-radius: 4px;
  background: linear-gradient(135deg, var(--accent), #9a6bff);
}

.actions {
  display: flex;
  align-items: center;
  gap: 8px;
}

.divider {
  width: 1px;
  height: 20px;
  background: var(--border);
  margin: 0 4px;
}

/* ---------- Buttons ---------- */
.btn {
  padding: 7px 14px;
  border: 1px solid var(--border);
  border-radius: var(--radius);
  background: var(--panel-2);
  color: var(--text);
  font-size: 13px;
  cursor: pointer;
  transition: background 0.15s, border-color 0.15s;
}

.btn:hover { border-color: var(--accent); }
.btn:disabled { opacity: 0.4; cursor: default; }
.btn:disabled:hover { border-color: var(--border); }

.btn-primary {
  background: var(--accent);
  border-color: var(--accent);
  color: #fff;
}

.btn-primary:hover { background: var(--accent-hover); }

.btn-small {
  padding: 4px 10px;
  font-size: 12px;
}

.btn-danger-ghost {
  color: var(--danger);
}

.btn-danger-ghost:hover { border-color: var(--danger); }

/* ---------- Workspace ---------- */
.workspace {
  display: grid;
  grid-template-columns: 220px 1fr 280px;
  flex: 1;
  min-height: 0;
}

.palette, .inspector {
  background: var(--panel);
  padding: 14px;
  overflow-y: auto;
}

.palette { border-right: 1px solid var(--border); }
.inspector { border-left: 1px solid var(--border); }

.palette h2, .inspector h2 {
  margin: 0 0 12px;
  font-size: 11px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: var(--muted);
}

.hint {
  color: var(--muted);
  font-size: 12px;
  line-height: 1.5;
  margin-top: 16px;
}

/* ---------- Palette items ---------- */
.palette-item {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 9px 10px;
  margin-bottom: 6px;
  background: var(--panel-2);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  cursor: grab;
  user-select: none;
  transition: border-color 0.15s, transform 0.1s;
}

.palette-item:hover {
  border-color: var(--accent);
  transform: translateY(-1px);
}

.palette-item:active { cursor: grabbing; }

.palette-icon {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 28px;
  height: 28px;
  border-radius: 6px;
  background: rgba(79, 140, 255, 0.12);
  color: var(--accent);
  flex-shrink: 0;
}

/* ---------- Canvas ---------- */
.canvas-area {
  display: flex;
  flex-direction: column;
  min-width: 0;
  background: var(--bg);
}

.canvas-toolbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 8px 16px;
  color: var(--muted);
  font-size: 12px;
  border-bottom: 1px solid var(--border);
}

.canvas-scroll {
  flex: 1;
  overflow: auto;
  display: flex;
  justify-content: center;
  padding: 24px;
}

.canvas {
  width: 960px;
  min-height: 600px;
  height: fit-content;
  background: #ffffff;
  border-radius: 10px;
  box-shadow: 0 8px 30px rgba(0, 0, 0, 0.35);
  padding: 16px;
  align-self: flex-start;
}

.canvas.drag-over {
  outline: 2px dashed var(--accent);
  outline-offset: -6px;
}

.canvas-empty {
  display: flex;
  align-items: center;
  justify-content: center;
  height: 560px;
  color: #a0a4ae;
  font-size: 15px;
  border: 2px dashed #dfe3ea;
  border-radius: 10px;
  pointer-events: none;
}

/* ---------- Canvas nodes ---------- */
.node {
  position: relative;
  margin: 6px 0;
  border: 1px solid transparent;
  border-radius: 6px;
  cursor: pointer;
}

.node:hover { border-color: rgba(79, 140, 255, 0.5); }

.node.selected {
  border-color: var(--accent);
  box-shadow: 0 0 0 2px rgba(79, 140, 255, 0.25);
}

.node.drop-before { box-shadow: 0 -3px 0 0 var(--accent); }
.node.drop-after { box-shadow: 0 3px 0 0 var(--accent); }
.node.drop-inside {
  border-color: var(--accent);
  box-shadow: inset 0 0 0 2px rgba(79, 140, 255, 0.4);
}

.node-tag {
  position: absolute;
  top: -10px;
  right: 6px;
  padding: 1px 8px;
  font-size: 10px;
  border-radius: 4px;
  background: var(--accent);
  color: #fff;
  opacity: 0;
  pointer-events: none;
  transition: opacity 0.1s;
  z-index: 2;
}

.node:hover .node-tag,
.node.selected .node-tag { opacity: 1; }

.node-children {
  padding: 4px 0 4px 0;
  min-height: 28px;
}

.node-children.empty::after {
  content: "Drop components here";
  display: block;
  padding: 8px;
  text-align: center;
  font-size: 11px;
  color: #b6bac4;
  border: 1px dashed #dfe3ea;
  border-radius: 6px;
  margin: 4px;
  pointer-events: none;
}

/* ---------- Inspector ---------- */
.field { margin-bottom: 12px; }

.field label {
  display: block;
  margin-bottom: 4px;
  font-size: 12px;
  color: var(--muted);
}

.field input[type="text"],
.field input[type="number"],
.field select,
.field textarea {
  width: 100%;
  padding: 7px 9px;
  border: 1px solid var(--border);
  border-radius: 6px;
  background: var(--panel-2);
  color: var(--text);
  font-size: 13px;
  font-family: inherit;
}

.field textarea { resize: vertical; min-height: 60px; }

.field input:focus, .field select:focus, .field textarea:focus {
  outline: none;
  border-color: var(--accent);
}

.field-row {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 8px;
}

.field input[type="color"] {
  width: 100%;
  height: 34px;
  padding: 2px;
  border: 1px solid var(--border);
  border-radius: 6px;
  background: var(--panel-2);
  cursor: pointer;
}

.inspector-type {
  display: inline-block;
  margin-bottom: 14px;
  padding: 3px 10px;
  border-radius: 20px;
  background: rgba(79, 140, 255, 0.12);
  color: var(--accent);
  font-size: 12px;
  font-weight: 600;
}

.inspector-actions {
  display: flex;
  gap: 6px;
  margin-top: 18px;
  padding-top: 14px;
  border-top: 1px solid var(--border);
}

.inspector-actions .btn { flex: 1; }

/* ---------- Preview modal ---------- */
.modal {
  position: fixed;
  inset: 0;
  background: rgba(10, 12, 16, 0.75);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 100;
}

.modal.hidden { display: none; }

.modal-frame {
  display: flex;
  flex-direction: column;
  width: min(1100px, 94vw);
  height: 88vh;
  background: var(--panel);
  border: 1px solid var(--border);
  border-radius: 12px;
  overflow: hidden;
}

.modal-bar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 14px;
  border-bottom: 1px solid var(--border);
}

.modal-title { font-weight: 600; }
.modal-actions { display: flex; gap: 6px; }

#previewFrame {
  flex: 1;
  border: none;
  background: #fff;
  align-self: center;
  width: 100%;
  transition: width 0.2s;
}

#previewFrame.mobile { width: 390px; }

/* ---------- Toast ---------- */
.toast {
  position: fixed;
  bottom: 22px;
  left: 50%;
  transform: translateX(-50%);
  padding: 10px 18px;
  background: var(--panel-2);
  border: 1px solid var(--accent);
  border-radius: 8px;
  font-size: 13px;
  z-index: 200;
  animation: toast-in 0.2s ease;
}

.toast.hidden { display: none; }

@keyframes toast-in {
  from { opacity: 0; transform: translate(-50%, 8px); }
  to { opacity: 1; transform: translate(-50%, 0); }
}

