+
+function clearCanvas() {
+  if (!doc.children.length) return;
+  if (!window.confirm("Remove all components from the canvas?")) return;
+  snapshot();
+  doc.children = [];
+  selectedId = null;
+  renderCanvas();
+  renderInspector();
+  saveLocal();
+}
+
+/* ------------------------- Canvas rendering ------------------------ */
+
+const els = {};
+
+function layoutStyle(props) {
+  const rules = [];
+  if (props._width && props._width !== "full") rules.push(`max-width:${props._width === "narrow" ? "380px" : "640px"}`);
+  if (Number(props._padding)) rules.push(`padding:${clamp(Number(props._padding), 0, 80)}px`);
+  if (props._textColor) rules.push(`color:${props._textColor}`);
+  if (props._bgColor) rules.push(`background:${props._bgColor}`);
+  return rules.join(";");
