"use strict";

/* =====================================================================
 * Mini App Builder — a zero-dependency drag & drop page builder.
 * State is a tree of nodes: { id, type, props, children }
 * ===================================================================== */

const STORAGE_KEY = "mini-app-builder-doc";

/* ---------------------------- Utilities ---------------------------- */

function uid() {
  return "n" + Math.random().toString(36).slice(2, 9);
}

function escapeHtml(value) {
  return String(value)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

function deepClone(value) {
  return JSON.parse(JSON.stringify(value));
}

function clamp(value, min, max) {
  return Math.min(max, Math.max(min, value));
}

/* ------------------------- Component library ------------------------ */
/*
 * Each component defines:
 *  - label / icon    : palette presentation
 *  - isContainer     : can hold children
 *  - defaults        : initial props
 *  - propFields      : schema that drives the inspector form
 *  - buildHtml       : inline HTML builder (shared by canvas + export)
 *
 * Prop conventions: layout props (_width, _padding, _textColor, _bgColor)
 * apply to every component; the rest are component-specific.
 */

const FIELD = {
  text: (key, label) => ({ kind: "text", key, label }),
  textarea: (key, label) => ({ kind: "textarea", key, label }),
  number: (key, label, min, max) => ({ kind: "number", key, label, min, max }),
  color: (key, label) => ({ kind: "color", key, label }),
  select: (key, label, options) => ({ kind: "select", key, label, options }),
};

const COMPONENTS = {
  heading: {
    label: "Heading",
    icon: '<svg width="16" height="16" viewBox="0 0 16 16" fill="none"><path d="M2 3h12M2 8h8M2 13h12" stroke="currentColor" stroke-width="2" stroke-linecap="round"/></svg>',
    defaults: { text: "Hello world", level: "h2", align: "left" },
    propFields: [
      FIELD.text("text", "Text"),
      FIELD.select("level", "Level", [
        { value: "h1", label: "H1" },
        { value: "h2", label: "H2" },
        { value: "h3", label: "H3" },
      ]),
      FIELD.select("align", "Align", [
        { value: "left", label: "Left" },
        { value: "center", label: "Center" },
        { value: "right", label: "Right" },
      ]),
    ],
    buildHtml(p) {
      const tag = ["h1", "h2", "h3"].includes(p.level) ? p.level : "h2";
      return `<${tag} style="margin:4px 0;text-align:${p.align}">${escapeHtml(p.text)}</${tag}>`;
    },
  },

  text: {
    label: "Text",
    icon: '<svg width="16" height="16" viewBox="0 0 16 16" fill="none"><path d="M2 4h12M2 8h12M2 12h7" stroke="currentColor" stroke-width="1.6" stroke-linecap="round"/></svg>',
    defaults: {
      text: "This is a paragraph. Select it and edit the text in the inspector on the right.",
      align: "left",
    },
    propFields: [
      FIELD.textarea("text", "Text"),
      FIELD.select("align", "Align", [
        { value: "left", label: "Left" },
        { value: "center", label: "Center" },
        { value: "right", label: "Right" },
      ]),
    ],
    buildHtml(p) {
      return `<p style="margin:4px 0;line-height:1.6;text-align:${p.align}">${escapeHtml(p.text)}</p>`;
    },
  },

  button: {
    label: "Button",
    icon: '<svg width="16" height="16" viewBox="0 0 16 16" fill="none"><rect x="1.5" y="4.5" width="13" height="7" rx="2" stroke="currentColor" stroke-width="1.6"/></svg>',
    defaults: {
      label: "Click me",
      variant: "primary",
      fullWidth: false,
      action: "none",
      message: "Hello from your app!",
      url: "https://example.com",
    },
    propFields: [
      FIELD.text("label", "Label"),
      FIELD.select("variant", "Style", [
        { value: "primary", label: "Primary" },
        { value: "secondary", label: "Secondary" },
      ]),
      FIELD.select("fullWidth", "Width", [
        { value: false, label: "Auto" },
        { value: true, label: "Full width" },
      ]),
      FIELD.select("action", "Click action", [
        { value: "none", label: "None" },
        { value: "alert", label: "Show alert" },
        { value: "link", label: "Open link" },
      ]),
      FIELD.text("message", "Alert message"),
      FIELD.text("url", "Link URL"),
    ],
    buildHtml(p) {
      const primary = p.variant !== "secondary";
      const style = [
        "padding:10px 18px",
        "border-radius:8px",
        "font-size:14px",
        "cursor:pointer",
        primary ? "background:#4f8cff;color:#fff;border:1px solid #4f8cff" : "background:#fff;color:#4f8cff;border:1px solid #4f8cff",
        p.fullWidth ? "width:100%" : "",
      ].join(";");
      return `<button data-action="${escapeHtml(p.action)}" data-message="${escapeHtml(p.message)}" data-url="${escapeHtml(p.url)}" style="${style}">${escapeHtml(p.label)}</button>`;
    },
  },

  image: {
    label: "Image",
    icon: '<svg width="16" height="16" viewBox="0 0 16 16" fill="none"><rect x="1.5" y="2.5" width="13" height="11" rx="2" stroke="currentColor" stroke-width="1.6"/><circle cx="5.5" cy="6.5" r="1.4" fill="currentColor"/><path d="M3 12l3.5-3.5 2.5 2.5 2-2L14 12" stroke="currentColor" stroke-width="1.4" stroke-linejoin="round"/></svg>',
    defaults: {
      src: "https://picsum.photos/800/320",
      alt: "Placeholder image",
      radius: 8,
    },
    propFields: [
      FIELD.text("src", "Image URL"),
      FIELD.text("alt", "Alt text"),
      FIELD.number("radius", "Corner radius", 0, 40),
    ],
    buildHtml(p) {
      const radius = clamp(Number(p.radius) || 0, 0, 100);
      return `<img src="${escapeHtml(p.src)}" alt="${escapeHtml(p.alt)}" style="max-width:100%;display:block;border-radius:${radius}px" />`;
    },
  },

  input: {
    label: "Input",
    icon: '<svg width="16" height="16" viewBox="0 0 16 16" fill="none"><rect x="1.5" y="4.5" width="13" height="7" rx="2" stroke="currentColor" stroke-width="1.6"/><path d="M5 8h4" stroke="currentColor" stroke-width="1.4" stroke-linecap="round"/></svg>',
    defaults: { label: "Email", placeholder: "you@example.com", inputType: "text" },
    propFields: [
      FIELD.text("label", "Label"),
      FIELD.text("placeholder", "Placeholder"),
      FIELD.select("inputType", "Type", [
        { value: "text", label: "Text" },
        { value: "email", label: "Email" },
        { value: "password", label: "Password" },
        { value: "number", label: "Number" },
      ]),
    ],
    buildHtml(p) {
      const type = ["text", "email", "password", "number"].includes(p.inputType) ? p.inputType : "text";
      return (
        `<label style="display:block;font-size:13px;color:#333">${escapeHtml(p.label)}` +
        `<input type="${type}" placeholder="${escapeHtml(p.placeholder)}" ` +
        `style="display:block;width:100%;margin-top:4px;padding:9px 10px;border:1px solid #ccd2dc;border-radius:8px;font-size:14px;box-sizing:border-box" /></label>`
      );
    },
  },

  divider: {
    label: "Divider",
    icon: '<svg width="16" height="16" viewBox="0 0 16 16" fill="none"><path d="M1 8h14" stroke="currentColor" stroke-width="1.6" stroke-linecap="round"/></svg>',
    defaults: {},
    propFields: [],
    buildHtml() {
      return `<hr style="border:none;border-top:1px solid #dfe3ea;margin:8px 0" />`;
    },
  },

  spacer: {
    label: "Spacer",
    icon: '<svg width="16" height="16" viewBox="0 0 16 16" fill="none"><path d="M8 1v14M3 3l5-2 5 2M3 13l5 2 5-2" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg>',
    defaults: { height: 24 },
    propFields: [FIELD.number("height", "Height (px)", 4, 400)],
    buildHtml(p) {
      const height = clamp(Number(p.height) || 24, 0, 600);
      return `<div style="height:${height}px"></div>`;
    },
  },

  row: {
    label: "Row",
    icon: '<svg width="16" height="16" viewBox="0 0 16 16" fill="none"><rect x="1.5" y="2.5" width="5.5" height="11" rx="1.5" stroke="currentColor" stroke-width="1.5"/><rect x="9" y="2.5" width="5.5" height="11" rx="1.5" stroke="currentColor" stroke-width="1.5"/></svg>',
    isContainer: true,
    defaults: { gap: 12 },
    propFields: [FIELD.number("gap", "Gap (px)", 0, 80)],
    buildHtml(p) {
      const gap = clamp(Number(p.gap) || 0, 0, 120);
      return `<div style="display:flex;gap:${gap}px;align-items:stretch">{{children}}</div>`;
    },
    childWrapHtml() {
      return `<div style="flex:1;min-width:0">{{children}}</div>`;
    },
  },

  card: {
    label: "Card",
    icon: '<svg width="16" height="16" viewBox="0 0 16 16" fill="none"><rect x="1.5" y="2.5" width="13" height="11" rx="2" stroke="currentColor" stroke-width="1.6"/><path d="M1.5 6h13" stroke="currentColor" stroke-width="1.4"/></svg>',
    isContainer: true,
    defaults: { padding: 16, radius: 12, shadow: true },
    propFields: [
      FIELD.number("padding", "Padding (px)", 0, 60),
      FIELD.number("radius", "Corner radius", 0, 40),
      FIELD.select("shadow", "Shadow", [
        { value: true, label: "On" },
        { value: false, label: "Off" },
      ]),
    ],
    buildHtml(p) {
      const style = [
        `padding:${clamp(Number(p.padding) || 0, 0, 80)}px`,
        `border-radius:${clamp(Number(p.radius) || 0, 0, 60)}px`,
        "background:#fff",
        "border:1px solid #e7eaf0",
        p.shadow ? "box-shadow:0 4px 14px rgba(15,23,42,0.08)" : "",
      ].join(";");
      return `<div style="${style}">{{children}}</div>`;
    },
  },
};

/* ------------------------------ State ------------------------------ */

let doc = { children: [] };
let selectedId = null;
let undoStack = [];
let redoStack = [];
const MAX_HISTORY = 100;

function createNode(type) {
  return {
    id: uid(),
    type,
    props: deepClone(COMPONENTS[type].defaults),
    children: COMPONENTS[type].isContainer ? [] : undefined,
  };
}

function findNodeAndParent(id, list, parent) {
  for (const node of list) {
    if (node.id === id) return { node, parent, list };
    if (node.children) {
      const found = findNodeAndParent(id, node.children, node);
      if (found) return found;
    }
  }
  return null;
}

function findNode(id) {
  if (!id) return null;
  const found = findNodeAndParent(id, doc.children, null);
  return found ? found.node : null;
}

function removeNode(id) {
  const found = findNodeAndParent(id, doc.children, null);
  if (!found) return false;
  found.list.splice(found.list.indexOf(found.node), 1);
  return true;
}

/* ---------------------------- History ------------------------------ */

function snapshot() {
  undoStack.push(JSON.stringify({ doc, selectedId }));
  if (undoStack.length > MAX_HISTORY) undoStack.shift();
  redoStack = [];
  updateHistoryButtons();
}

function restore(serialized) {
  const state = JSON.parse(serialized);
  doc = state.doc;
  selectedId = state.selectedId;
  renderCanvas();
  renderInspector();
  saveLocal();
  updateHistoryButtons();
}

function undo() {
  if (!undoStack.length) return;
  redoStack.push(JSON.stringify({ doc, selectedId }));
  restore(undoStack.pop());
}

function redo() {
  if (!redoStack.length) return;
  undoStack.push(JSON.stringify({ doc, selectedId }));
  restore(redoStack.pop());
}

function updateHistoryButtons() {
  els.undoBtn.disabled = undoStack.length === 0;
  els.redoBtn.disabled = redoStack.length === 0;
}

/* -------------------------- Persistence ---------------------------- */

function saveLocal() {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify({ doc, selectedId }));
  } catch (err) {
    /* storage unavailable — ignore */
  }
}

function loadLocal() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return false;
    const state = JSON.parse(raw);
    if (!state || !Array.isArray(state.doc.children)) return false;
    doc = state.doc;
    selectedId = state.selectedId;
    return true;
  } catch (err) {
    return false;
  }
}

function loadStarter() {
  const hero = createNode("heading");
  hero.props.text = "Welcome to your app";
  hero.props.level = "h1";

  const intro = createNode("text");
  intro.props.text = "Drag components from the left panel, click them to edit, then preview or export your app as a standalone HTML file.";

  const button = createNode("button");
  button.props.label = "Get started";
  button.props.action = "alert";

  const card = createNode("card");
  card.children = [hero, intro, button];

  const title = createNode("heading");
  title.props.text = "Mini App Builder";
  title.props.level = "h2";

  doc.children = [title, card];
}

/* --------------------------- Mutations ----------------------------- */

function addNode(type, targetList, index) {
  snapshot();
  const node = createNode(type);
  const list = targetList || doc.children;
  const at = index === undefined || index === null ? list.length : clamp(index, 0, list.length);
  list.splice(at, 0, node);
  selectedId = node.id;
  renderCanvas();
  renderInspector();
  saveLocal();
}

function moveNode(id, targetList, index) {
  const found = findNodeAndParent(id, doc.children, null);
  if (!found) return;
  // Guard: cannot drop a container into its own subtree.
  if (findNodeAndParent(targetListOwnerId, found.node.children || [], found.node)) return;

  snapshot();
  found.list.splice(found.list.indexOf(found.node), 1);
  const at = index === undefined || index === null ? targetList.length : clamp(index, 0, targetList.length);
  targetList.splice(at, 0, found.node);
  renderCanvas();
  renderInspector();
  saveLocal();
}

// helper used only by the guard above (id of list owner, set before calls)
let targetListOwnerId = null;

function updateProp(id, key, value) {
  const node = findNode(id);
  if (!node) return;
  snapshot();
  node.props[key] = value;
  renderCanvas();
  saveLocal();
}

function duplicateNode(id) {
  const found = findNodeAndParent(id, doc.children, null);
  if (!found) return;
  snapshot();
  const copy = deepClone(found.node);
  reassignIds(copy);
  found.list.splice(found.list.indexOf(found.node) + 1, 0, copy);
  selectedId = copy.id;
  renderCanvas();
  renderInspector();
  saveLocal();
}

function reassignIds(node) {
  node.id = uid();
  (node.children || []).forEach(reassignIds);
}

function deleteNode(id) {
  snapshot();
  removeNode(id);
  if (selectedId === id || !findNode(selectedId)) selectedId = null;
  renderCanvas();
  renderInspector();
  saveLocal();
}

function clearCanvas() {
  if (!doc.children.length) return;
  if (!window.confirm("Remove all components from the canvas?")) return;
  snapshot();
  doc.children = [];
  selectedId = null;
  renderCanvas();
  renderInspector();
  saveLocal();
}

/* ------------------------- Canvas rendering ------------------------ */

const els = {};

function layoutStyle(props) {
  const rules = [];
  if (props._width && props._width !== "full") rules.push(`max-width:${props._width === "narrow" ? "380px" : "640px"}`);
  if (Number(props._padding)) rules.push(`padding:${clamp(Number(props._padding), 0, 80)}px`);
  if (props._textColor) rules.push(`color:${props._textColor}`);
  if (props._bgColor) rules.push(`background:${props._bgColor}`);
  return rules.join(";");
}

function buildNodeHtml(node, forExport) {
  const comp = COMPONENTS[node.type];
  let inner = comp.buildHtml(node.props);

  if (comp.isContainer) {
    let childrenHtml = (node.children || []).map((child) => buildNodeHtml(child, forExport)).join("");
    if (comp.childWrapHtml) {
      // wrap each child in its flex cell
      childrenHtml = (node.children || [])
        .map((child) => comp.childWrapHtml(child.props).replace("{{children}}", buildNodeHtml(child, forExport)))
        .join("");
    }
    inner = inner.replace("{{children}}", childrenHtml);
  }

  const layout = layoutStyle(node.props);
  if (layout) {
    inner = `<div style="${layout}">${inner}</div>`;
  }
  return inner;
}

function renderCanvas() {
  els.canvas.innerHTML = "";

  if (doc.children.length === 0) {
    const empty = document.createElement("div");
    empty.className = "canvas-empty";
    empty.textContent = "Drag components here to build your app";
    els.canvas.appendChild(empty);
    return;
  }

  for (const node of doc.children) {
    els.canvas.appendChild(renderNode(node, doc.children));
  }
}

function renderNode(node, ownerList) {
  const comp = COMPONENTS[node.type];
  const wrap = document.createElement("div");
  wrap.className = "node" + (node.id === selectedId ? " selected" : "");
  wrap.dataset.id = node.id;
  wrap.draggable = true;

  const tag = document.createElement("span");
  tag.className = "node-tag";
  tag.textContent = comp.label;
  wrap.appendChild(tag);

  const content = document.createElement("div");
  content.innerHTML = buildNodeHtml(node, false);

  if (comp.isContainer) {
    // Replace rendered children with interactive child nodes.
    const slots = content.querySelectorAll("[data-slot]");
    content.innerHTML = comp.buildHtml(node.props).replace("{{children}}", `<div data-slot="root"></div>`);
    let slotRoot = content.querySelector('[data-slot="root"]');

    if (comp.childWrapHtml) {
      // flex-like container: create one interactive drop cell per child
      slotRoot.remove();
      const container = content.firstElementChild;
      for (const child of node.children) {
        const cell = document.createElement("div");
        cell.style.cssText = "flex:1;min-width:0";
        cell.appendChild(renderNode(child, node.children));
        container.appendChild(cell);
      }
      const addCell = document.createElement("div");
      addCell.style.cssText = "flex:1;min-width:0";
      addCell.appendChild(makeChildrenZone(node));
      container.appendChild(addCell);
    } else {
      const zone = makeChildrenZone(node);
      for (const child of node.children) zone.appendChild(renderNode(child, node.children));
      slotRoot.replaceWith(zone);
    }
  }

  wrap.appendChild(content);

  wrap.addEventListener("click", (event) => {
    event.stopPropagation();
    selectNode(node.id);
  });

  wrap.addEventListener("dragstart", (event) => {
    event.stopPropagation();
    event.dataTransfer.setData("text/move-node", node.id);
    event.dataTransfer.effectAllowed = "move";
  });

  // Reorder / drop-into support.
  wrap.addEventListener("dragover", (event) => {
    const mode = getDragMode(event);
    if (!mode) return;
    event.preventDefault();
    event.stopPropagation();
    clearDropHints();
    const position = dropPosition(event, wrap, comp);
    wrap.classList.add(position === "inside" ? "drop-inside" : position === "before" ? "drop-before" : "drop-after");
    wrap.dataset.dropPosition = position;
  });

  wrap.addEventListener("dragleave", () => {
    wrap.classList.remove("drop-before", "drop-after", "drop-inside");
  });

  wrap.addEventListener("drop", (event) => {
    event.preventDefault();
    event.stopPropagation();
    const position = wrap.dataset.dropPosition || "after";
    wrap.classList.remove("drop-before", "drop-after", "drop-inside");
    delete wrap.dataset.dropPosition;

    const newType = event.dataTransfer.getData("text/new-component");
    const moveId = event.dataTransfer.getData("text/move-node");
    if (!newType && !moveId) return;

    if (position === "inside" && comp.isContainer) {
      if (moveId && isDescendant(moveId, node.id)) return; // no cycles
      if (newType) addNode(newType, node.children, node.children.length);
      else moveNode(moveId, node.children, node.children.length);
      return;
    }

    const index = ownerList.indexOf(node) + (position === "after" ? 1 : 0);
    if (newType) {
      addNode(newType, ownerList, index);
    } else {
      if (moveId === node.id) return;
      if (isDescendant(node.id, moveId)) return;
      moveNode(moveId, ownerList, index);
    }
  });

  return wrap;
}

function makeChildrenZone(node) {
  const zone = document.createElement("div");
  zone.className = "node-children" + ((node.children || []).length ? "" : " empty");
  zone.dataset.ownerId = node.id;

  zone.addEventListener("dragover", (event) => {
    const mode = getDragMode(event);
    if (!mode) return;
    event.preventDefault();
    event.stopPropagation();
    zone.closest(".node").classList.add("drop-inside");
  });

  zone.addEventListener("drop", (event) => {
    event.preventDefault();
    event.stopPropagation();
    clearDropHints();
    const newType = event.dataTransfer.getData("text/new-component");
    const moveId = event.dataTransfer.getData("text/move-node");
    if (moveId && (moveId === node.id || isDescendant(node.id, moveId))) return;
    if (newType) addNode(newType, node.children, node.children.length);
    else if (moveId) moveNode(moveId, node.children, node.children.length);
  });

  return zone;
}

function dropPosition(event, wrap, comp) {
  const rect = wrap.getBoundingClientRect();
  const ratio = (event.clientY - rect.top) / Math.max(rect.height, 1);
  if (comp.isContainer && ratio > 0.3 && ratio < 0.7) return "inside";
  return ratio < 0.5 ? "before" : "after";
}

function getDragMode(event) {
  const types = event.dataTransfer.types;
  if (types.includes("text/new-component")) return "new";
  if (types.includes("text/move-node")) return "move";
  return null;
}

function clearDropHints() {
  els.canvas.querySelectorAll(".drop-before,.drop-after,.drop-inside").forEach((el) => {
    el.classList.remove("drop-before", "drop-after", "drop-inside");
  });
}

function isDescendant(maybeDescendantId, ancestorId) {
  const ancestor = findNode(ancestorId);
  if (!ancestor || !ancestor.children) return false;
  return !!findNodeAndParent(maybeDescendantId, ancestor.children, ancestor);
}

function selectNode(id) {
  selectedId = id;
  els.canvas.querySelectorAll(".node.selected").forEach((el) => el.classList.remove("selected"));
  const el = els.canvas.querySelector(`.node[data-id="${id}"]`);
  if (el) el.classList.add("selected");
  renderInspector();
}

/* --------------------------- Inspector ----------------------------- */

const LAYOUT_FIELDS = [
  FIELD.select("_width", "Width", [
    { value: "full", label: "Full" },
    { value: "wide", label: "Wide (640px)" },
    { value: "narrow", label: "Narrow (380px)" },
  ]),
  FIELD.number("_padding", "Extra padding (px)", 0, 80),
  FIELD.color("_textColor", "Text color"),
  FIELD.color("_bgColor", "Background color"),
];

function renderInspector() {
  const node = findNode(selectedId);
  els.inspectorBody.innerHTML = "";

  if (!node) {
    const hint = document.createElement("p");
    hint.className = "hint";
    hint.textContent = "Select a component on the canvas to edit its properties.";
    els.inspectorBody.appendChild(hint);
    return;
  }

  const comp = COMPONENTS[node.type];

  const badge = document.createElement("span");
  badge.className = "inspector-type";
  badge.textContent = comp.label;
  els.inspectorBody.appendChild(badge);

  for (const field of comp.propFields) {
    els.inspectorBody.appendChild(makeField(field, node));
  }

  if (comp.propFields.length) {
    els.inspectorBody.appendChild(makeSectionLabel("Layout"));
  }
  for (const field of LAYOUT_FIELDS) {
    els.inspectorBody.appendChild(makeField(field, node));
  }

  const actions = document.createElement("div");
  actions.className = "inspector-actions";

  const dup = document.createElement("button");
  dup.className = "btn btn-small";
  dup.textContent = "Duplicate";
  dup.addEventListener("click", () => duplicateNode(node.id));

  const del = document.createElement("button");
  del.className = "btn btn-small btn-danger-ghost";
  del.textContent = "Delete";
  del.addEventListener("click", () => deleteNode(node.id));

  actions.appendChild(dup);
  actions.appendChild(del);
  els.inspectorBody.appendChild(actions);
}

function makeSectionLabel(text) {
  const label = document.createElement("h2");
  label.style.marginTop = "18px";
  label.textContent = text;
  return label;
}

function makeField(field, node) {
  const wrap = document.createElement("div");
  wrap.className = "field";

  const label = document.createElement("label");
  label.textContent = field.label;
  wrap.appendChild(label);

  let input;
  const current = node.props[field.key];

  if (field.kind === "textarea") {
    input = document.createElement("textarea");
    input.value = current ?? "";
  } else if (field.kind === "select") {
    input = document.createElement("select");
    for (const opt of field.options) {
      const option = document.createElement("option");
      option.value = String(opt.value);
      option.textContent = opt.label;
      if (String(current) === String(opt.value)) option.selected = true;
      input.appendChild(option);
    }
  } else if (field.kind === "color") {
    input = document.createElement("input");
    input.type = "color";
    input.value = current || "#1a1d24";
  } else if (field.kind === "number") {
    input = document.createElement("input");
    input.type = "number";
    if (field.min !== undefined) input.min = field.min;
    if (field.max !== undefined) input.max = field.max;
    input.value = current ?? "";
  } else {
    input = document.createElement("input");
    input.type = "text";
    input.value = current ?? "";
  }

  input.addEventListener("input", () => {
    let value = input.value;
    if (field.kind === "number") value = value === "" ? 0 : Number(value);
    if (field.kind === "select") {
      const opt = field.options.find((o) => String(o.value) === value);
      value = opt ? opt.value : value;
    }
    updateProp(node.id, field.key, value);
    // keep selection outline after re-render
    const el = els.canvas.querySelector(`.node[data-id="${node.id}"]`);
    if (el) el.classList.add("selected");
  });

  wrap.appendChild(input);
  return wrap;
}

/* ----------------------------- Palette ----------------------------- */

function renderPalette() {
  for (const [type, comp] of Object.entries(COMPONENTS)) {
    const item = document.createElement("div");
    item.className = "palette-item";
    item.draggable = true;

    const icon = document.createElement("span");
    icon.className = "palette-icon";
    icon.innerHTML = comp.icon;

    const name = document.createElement("span");
    name.textContent = comp.label;

    item.appendChild(icon);
    item.appendChild(name);

    item.addEventListener("dragstart", (event) => {
      event.dataTransfer.setData("text/new-component", type);
      event.dataTransfer.effectAllowed = "copy";
    });

    item.addEventListener("dblclick", () => addNode(type));

    els.paletteList.appendChild(item);
  }
}

/* --------------------------- Export / preview ----------------------- */

const EXPORT_CSS = `
  * { box-sizing: border-box; }
  body { margin: 0; padding: 32px 16px; background: #f4f6fa; color: #1a1d24;
         font-family: "Segoe UI", system-ui, -apple-system, sans-serif; }
  .app { max-width: 720px; margin: 0 auto; }
  .app > * + * { margin-top: 10px; }
`;

const EXPORT_JS = `
  document.addEventListener("click", function (event) {
    var btn = event.target.closest("[data-action]");
    if (!btn) return;
    var action = btn.getAttribute("data-action");
    if (action === "alert") window.alert(btn.getAttribute("data-message") || "Hello!");
    if (action === "link") window.open(btn.getAttribute("data-url"), "_blank", "noopener");
  });
`;

function generateHtml() {
  const body = doc.children.map((node) => buildNodeHtml(node, true)).join("\n      ");
  return [
    "<!DOCTYPE html>",
    '<html lang="en">',
    "<head>",
    '  <meta charset="UTF-8" />',
    '  <meta name="viewport" content="width=device-width, initial-scale=1.0" />',
    "  <title>My App</title>",
    "  <style>" + EXPORT_CSS + "  </style>",
    "</head>",
    "<body>",
    '  <main class="app">',
    "      " + body,
    "  </main>",
    "  <script>" + EXPORT_JS + "  </scr" + "ipt>",
    "</body>",
    "</html>",
  ].join("\n");
}

function exportApp() {
  const blob = new Blob([generateHtml()], { type: "text/html" });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = "my-app.html";
  document.body.appendChild(link);
  link.click();
  link.remove();
  setTimeout(() => URL.revokeObjectURL(url), 1000);
  showToast("Exported my-app.html");
}

function openPreview() {
  els.previewFrame.srcdoc = generateHtml();
  els.previewModal.classList.remove("hidden");
}

function closePreview() {
  els.previewModal.classList.add("hidden");
  els.previewFrame.srcdoc = "";
}

/* ------------------------------ Toast ------------------------------ */

let toastTimer = null;
function showToast(message) {
  els.toast.textContent = message;
  els.toast.classList.remove("hidden");
  clearTimeout(toastTimer);
  toastTimer = setTimeout(() => els.toast.classList.add("hidden"), 2200);
}

/* ------------------------------- Init ------------------------------ */

function init() {
  els.canvas = document.getElementById("canvas");
  els.paletteList = document.getElementById("paletteList");
  els.inspectorBody = document.getElementById("inspectorBody");
  els.undoBtn = document.getElementById("undoBtn");
  els.redoBtn = document.getElementById("redoBtn");
  els.previewBtn = document.getElementById("previewBtn");
  els.exportBtn = document.getElementById("exportBtn");
  els.clearBtn = document.getElementById("clearBtn");
  els.previewModal = document.getElementById("previewModal");
  els.previewFrame = document.getElementById("previewFrame");
  els.toast = document.getElementById("toast");

  renderPalette();

  if (!loadLocal()) {
    loadStarter();
    saveLocal();
  }

  renderCanvas();
  renderInspector();
  updateHistoryButtons();

  // Canvas-level drop (append to root).
  els.canvas.addEventListener("dragover", (event) => {
    if (!getDragMode(event)) return;
    event.preventDefault();
    els.canvas.classList.add("drag-over");
  });
  els.canvas.addEventListener("dragleave", (event) => {
    if (event.target === els.canvas) els.canvas.classList.remove("drag-over");
  });
  els.canvas.addEventListener("drop", (event) => {
    event.preventDefault();
    els.canvas.classList.remove("drag-over");
    const newType = event.dataTransfer.getData("text/new-component");
    const moveId = event.dataTransfer.getData("text/move-node");
    if (newType) addNode(newType, doc.children, doc.children.length);
    else if (moveId) moveNode(moveId, doc.children, doc.children.length);
  });
  els.canvas.addEventListener("click", () => selectNode(null));

  // Toolbar actions.
  els.undoBtn.addEventListener("click", undo);
  els.redoBtn.addEventListener("click", redo);
  els.clearBtn.addEventListener("click", clearCanvas);
  els.previewBtn.addEventListener("click", openPreview);
  els.exportBtn.addEventListener("click", exportApp);
  document.getElementById("closePreview").addEventListener("click", closePreview);
  document.getElementById("previewDesktop").addEventListener("click", () => els.previewFrame.classList.remove("mobile"));
  document.getElementById("previewMobile").addEventListener("click", () => els.previewFrame.classList.add("mobile"));
  els.previewModal.addEventListener("click", (event) => {
    if (event.target === els.previewModal) closePreview();
  });

  // Keyboard shortcuts.
  document.addEventListener("keydown", (event) => {
    const editing = /^(INPUT|TEXTAREA|SELECT)$/.test(document.activeElement.tagName);
    if ((event.ctrlKey || event.metaKey) && event.key.toLowerCase() === "z") {
      event.preventDefault();
      if (event.shiftKey) redo();
      else undo();
      return;
    }
    if ((event.key === "Delete" || event.key === "Backspace") && selectedId && !editing) {
      event.preventDefault();
      deleteNode(selectedId);
    }
    if (event.key === "Escape") closePreview();
  });
}

document.addEventListener("DOMContentLoaded", init);

