const PROJECTS_KEY = "mini-app-builder-projects";
let currentName = null;

function getProjects() { try { return JSON.parse(localStorage.getItem(PROJECTS_KEY)) || {}; } catch { return {}; } }
function setProjects(map) { try { localStorage.setItem(PROJECTS_KEY, JSON.stringify(map)); } catch {} }

function saveProject() {
  const name = window.prompt("Project name:", currentName || "My App");
  if (!name) return;
  const trimmed = name.trim().slice(0, 60);
  if (!trimmed) return;
  const projects = getProjects();
  projects[trimmed] = { doc: deepClone(doc), savedAt: Date.now() };
  setProjects(projects);
  currentName = trimmed;
  saveLocal();
  updateTitle();
  showToast(`Saved "${trimmed}"`);
}

function loadProject(name) {
  const projects = getProjects();
  const entry = projects[name];
  if (!entry) { showToast("Project not found"); return; }
  snapshot();
  doc = deepClone(entry.doc);
  selectedId = null;
  currentName = name;
  renderCanvas(); renderInspector(); saveLocal(); updateTitle();
  closeProjects();
  showToast(`Loaded "${name}"`);
}

function deleteProject(name) {
  if (!window.confirm(`Delete saved project "${name}"?`)) return;
  const projects = getProjects();
  delete projects[name];
  setProjects(projects);
  renderProjectsList();
}

function exportProjectFile(name) {
  const projects = getProjects();
  const entry = projects[name];
  if (!entry) return;
  downloadJson({ name, doc: entry.doc, exportedAt: new Date().toISOString() }, name);
}
