Import:
```js
function importProjectFile(file) {
  const reader = new FileReader();
  reader.onload = () => {
    try {
      const parsed = JSON.parse(reader.result);
      const rawDoc = parsed && Array.isArray(parsed.children) ? parsed : parsed && parsed.doc;
      const clean = sanitizeDoc(rawDoc);
      if (!clean) throw new Error("bad file");
      snapshot();
      doc = clean;
      selectedId = null;
      currentName = typeof parsed.name === "string" ? parsed.name.slice(0,60) : file.name.replace(/\.json$/i, "");
      renderCanvas(); renderInspector(); saveLocal(); updateTitle();
      closeProjects();
      showToast("Project imported");
    } catch (e) {
      showToast("Import failed: not a valid project file");
    }
  };
  reader.readAsText(file);
}

function sanitizeDoc(raw) {
  if (!raw || !Array.isArray(raw.children)) return null;
  function cleanNode(n) {
    if (!n || typeof n !== "object" || !COMPONENTS[n.type]) return null;
    const node = { id: uid(), type: n.type, props: {}, children: undefined };
    const defaults = COMPONENTS[n.type].defaults;
    node.props = deepClone(defaults);
    if (n.props && typeof n.props === "object") {
      for (const [k, v] of Object.entries(n.props)) {
        if (typeof v === "string" || typeof v === "number" || typeof v === "boolean") node.props[k] = v;
      }
    }
    if (COMPONENTS[n.type].isContainer) {
      node.children = [];
      if (Array.isArray(n.children)) {
        for (const c of n.children) { const cn = cleanNode(c); if (cn) node.children.push(cn); }
      }
    }
    return node;
  }
  const out = { children: [] };
  for (const c of raw.children) { const cn = cleanNode(c); if (cn) out.children.push(cn); }
  return out;
}
```
Nice — sanitize merges with defaults so old files missing new props still work.

